from pathlib import Path
import re
p = Path\(r"C:/Users/12712/.claude/projects/F--1work-------/c4131582-c5ce-40d5-9392-50659df4264c/tool-results/br3fq6zpd.txt"\)
lines = p.read_text\(encoding='utf-8', errors='replace'\).splitlines\(\)
cur=None
new_line=0
for line in lines:
    if line.startswith\('diff --git '\):
        m = re.match\(r'diff --git a/\(.*?\) b/\(.*\)', line\)
        cur = m.group\(2\) if m else None
        continue
    if line.startswith\('@@ '\):
        m = re.search\(r'\\+\(\\d+\)\(?:,\(\\d+\)\)?', line\)
        if m:
            new_line = int\(m.group\(1\)\) - 1
        continue
    if cur is None:
        continue
    if line.startswith\('+'\) and not line.startswith\('+++'\):
        new_line += 1
        content = line[1:]
        s = content.strip\(\)
        if re.match\(r'\(async\\s+\)?function\\s+[A-Za-z_][A-Za-z0-9_]*\\s*\\\(', s\) or re.match\(r'const\\s+[A-Za-z_][A-Za-z0-9_]*\\s*=\\s*\(async\\s*\)?\\\([^\\\)]*\\\)\\s*=>', s\) or re.match\(r'const\\s+[A-Za-z_][A-Za-z0-9_]*\\s*=\\s*\(async\\s+\)?function\\s*\\\(', s\):
            print\(f"{cur}:{new_line}: {s}"\)
    elif line.startswith\('-'\) and not line.startswith\('---'\):
        pass
    else:
        if not line.startswith\('\\\\'\):
            new_line += 1
PY)
